package genxsolution.vms.vmsbackend.employee_hr_management.payroll_deduction.service;
import genxsolution.vms.vmsbackend.employee_hr_management.exception.HrResourceNotFoundException; import genxsolution.vms.vmsbackend.employee_hr_management.payroll_deduction.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.payroll_deduction.mapper.PayrollDeductionMapper; import genxsolution.vms.vmsbackend.employee_hr_management.payroll_deduction.repository.PayrollDeductionRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class PayrollDeductionService { private final PayrollDeductionRepository repository; private final PayrollDeductionMapper mapper; public PayrollDeductionService(PayrollDeductionRepository repository,PayrollDeductionMapper mapper){this.repository=repository;this.mapper=mapper;} public List<PayrollDeductionResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public PayrollDeductionResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("PayrollDeduction", id.toString())); } public PayrollDeductionResponse create(PayrollDeductionUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public PayrollDeductionResponse update(UUID id,PayrollDeductionUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("PayrollDeduction", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new HrResourceNotFoundException("PayrollDeduction", id.toString()); } }
